// ── MCP forge_start verify command ──────────────────────────

describe('verify MCP: forge_start command enum', () => {
  test('mcp.ts forge_start accepts verify as a command', async () => {
    const mcpPath = path.join(import.meta.dirname, 'mcp.ts');
    const content = await fs.readFile(mcpPath, 'utf-8');

    // The command enum in the zod schema should include 'verify'
    // z.enum(['define', 'proof', 'prove', 'run', 'audit', 'verify'])
    expect(content).toContain("'verify'");

    // Find the z.enum line for forge_start command
    const enumMatch = content.match(/z\.enum\(\[([^\]]+)\]/);
    expect(enumMatch).not.toBeNull();
    const enumValues = enumMatch![1];
    expect(enumValues).toContain('verify');
  });

  test('forge_start command enum includes all expected commands', async () => {
    const mcpPath = path.join(import.meta.dirname, 'mcp.ts');
    const content = await fs.readFile(mcpPath, 'utf-8');

    const enumMatch = content.match(/z\.enum\(\[([^\]]+)\]/);
    expect(enumMatch).not.toBeNull();
    const enumStr = enumMatch![1];

    for (const cmd of ['define', 'proof', 'run', 'audit', 'verify']) {
      expect(enumStr).toContain(`'${cmd}'`);
    }
  });

  test('prove backward-compatible alias is in the enum', async () => {
    const mcpPath = path.join(import.meta.dirname, 'mcp.ts');
    const content = await fs.readFile(mcpPath, 'utf-8');

    const enumMatch = content.match(/z\.enum\(\[([^\]]+)\]/);
    expect(enumMatch).not.toBeNull();
    expect(enumMatch![1]).toContain('prove');
  });
});

